  ('locality-6e2f88c7-moex-00307', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-110-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '甲乙為兄妹，乙丙為夫妻，丙丁間為父子關係，丁戊為夫妻，戊庚為姊弟。下列關於親屬關係之 敘述，何者錯誤？', '["如果丁之血緣從丙所出，則庚為丙之三親等旁系姻親", "如果丁之血緣亦從乙所出，則甲為丁之三親等旁系血親", "甲庚間無親屬關係", "丙庚間無親屬關係"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:49+00:00", "source_pdf_sha1": "a4b613a63dd0", "answer_pdf_sha1": "7542e7107b70", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "315", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00308', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-110-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '關於繼承人開具遺產清冊與被繼承人之債權人之陳報，下列敘述，何者正確？', '["繼承人應於知悉其得繼承之時起6個月內開具遺產清冊陳報於稅捐機關與法院強制執行處", "被繼承人之全體債權人應於繼承開始時起6個月內，共同向法院聲請命全體繼承人以書面提出 遺產清冊於債權人會議", "繼承人有數人時，其中一人已於知悉其得繼承之時起6個月內開具遺產清冊陳報於稅捐機關與 法院強制執行處者，其他繼承人視為已經陳報", "繼承人於知悉其得繼承之時起3個月內開具遺產清冊陳報法院時，法院應依公示催告程序公告， 命被繼承人之債權人於一定期限內報明其債權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:49+00:00", "source_pdf_sha1": "a4b613a63dd0", "answer_pdf_sha1": "7542e7107b70", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "315", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00309', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-110-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '下列關於口授遺囑之敘述，何者錯誤？', '["口授遺囑為特別方式之遺囑，較普通方式之遺囑簡略", "口授遺囑係為適應遺囑人有生命危急或特殊情形而設", "口授遺囑，縱使遺囑人能依其他方式為遺囑而不為之者，仍不影響該遺囑之效力", "口授遺囑，應由見證人中之一人或利害關係人，於為遺囑人死亡後三個月內，提經親屬會議認 定其真偽"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:49+00:00", "source_pdf_sha1": "a4b613a63dd0", "answer_pdf_sha1": "7542e7107b70", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "315", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00310', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-110-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '甲於2017年因子女乙結婚贈與新臺幣（下同）200萬元，因子女丙結婚贈與100萬元。甲於2018 年死亡時留有200萬元，並對丁積欠債務100萬元未清償；甲於遺囑中遺贈戊100萬元。下列敘 述，何者正確？', '["甲對乙之贈與為生前特種贈與，故不視為所得遺產", "丙就甲之遺產有特留分額為100萬元", "乙得對受遺贈人戊主張扣減權", "乙之應繼分較丙多出100萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:49+00:00", "source_pdf_sha1": "a4b613a63dd0", "answer_pdf_sha1": "7542e7107b70", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "315", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
